var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"역병의 마수가 이곳까지 덮친 것인가?","JPN":"疫病の魔手がここまで押し寄せてきたのか？","ENG":"Has the plague already reached these lands?","TWN":"瘟疫已蔓延至此了？"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"마왕이 사라졌음에도 역병의 기세는 조금도 누그러들지 않았구나.","JPN":"魔王が消えても、疫病の勢いは少しも収まっていないのだな。","ENG":"Even with the Demon Lord gone, the plague has not slowed down at all.","TWN":"魔王消失後，瘟疫傳播的趨勢也絲毫沒有減弱。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"…예하! 여기요!","JPN":"……猊下！　ここです！","ENG":"...Your Eminence! Over here!","TWN":"……主教！這邊！"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"아직 살아 계신 분을 찾았어요!","JPN":"まだ生きている方を見つけました！","ENG":"I found someone still alive!","TWN":"找到了倖存者！"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"WOMEN_CULTIST_NULL_EXTRA","text":{"KOREA":"커억… 컥, 컥…","JPN":"ぐっ……がはっ……くうっ……","ENG":"Kurgh... K-kuh...","TWN":"咳……咳咳……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"이미 목덜미 아래로는 전부 검게 잠식되었군.","JPN":"既に首から下は黒く侵食されておるな。","ENG":"The plague has already consumed her body from the neck down.","TWN":"脖子以下的身體已經被徹底侵蝕了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"마물로부터 안전한 곳에 숨어있었지만, 역병을 피하진 못했구나.","JPN":"村から逃げ出し安全な場所に隠れていても、疫病からは逃れられなかったのか。","ENG":"Though she was safe from the monsters, she could not hide from the plague.","TWN":"雖然躲到了一個遠離怪物的地方，但還是沒能逃過瘟疫的侵襲。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"어, 얼른 데려가죠! 교단까지 조금 멀긴 하지만, 도착하면 의사분들이 도와줄 거예요!","JPN":"は、早く連れて行きましょう！　教団までは距離がありますが、行けばお医者さんが助けてくれるはずです！","ENG":"W-we need to get her help! The Order is a little far, but I'm sure the doctors will help her once we bring her to them!","TWN":"快、快帶走吧！雖然這裡離教團有點遠，但至少能得到醫生們的幫助！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"역병을 치료할 수 있는 의사는 없다.","JPN":"疫病を治療できる医者はおらん。","ENG":"There is no doctor who can cure the plague.","TWN":"沒有醫生能治癒瘟疫。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"이 여인을 데려가봐야 주민들의 역병에 대한 두려움만 자극할 뿐이겠지.","JPN":"この女を連れて行っても疫病に対する住民たちの恐怖心を刺激するだけであろう。","ENG":"We will only instill more fear of the plague in the residents if we bring her with us.","TWN":"把人帶走只會加劇村民對瘟疫的恐懼。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"그럼… 어떻게 하죠?","JPN":"では……どうしましょう。","ENG":"Then... What do we do?","TWN":"那麼……我們該怎麼辦？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"지금 할 수 있는 최선은, 병자가 변이를 겪으며 얻는 고통을 조금이라도 덜어주는 것이다.","JPN":"今できることは、病人が変異する時の苦痛を少しでも和らげてあげることだ。","ENG":"The best we can do for her is to spare her from the pain of transformation.","TWN":"我們現在能做的就是盡可能減輕病人在變異過程中的痛苦。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"WOMEN_CULTIST_NULL_EXTRA","text":{"KOREA":"아… 아아….","JPN":"あ……ああ……","ENG":"Ah... Ahh...","TWN":"啊……啊……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"WOMEN_CULTIST_NULL_EXTRA","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"빛의 품에서, 상냥한 안식을.","JPN":"光に包まれ、優しい安らぎを。","ENG":"May you find a peaceful rest in the light's embrace.","TWN":"在光明的懷抱中安息吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"…죄송해요. 제가 했어야 하는 건데.","JPN":"……ごめんなさい。私がやらなければいけないのに。","ENG":"...I'm sorry. I should've been the one to do it.","TWN":"……對不起，本應該是我來做的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"이또한 나의 책무이니. 신경 쓰지 말아라.","JPN":"これもまた、我の責務だ。気にするな。","ENG":"This is my responsibility. No concern of yours.","TWN":"這也是我的職責。沒關係"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};